    },
    "profile_slug": {
      "type": "string",
      "minLength": 1,
      "description": "Stable identifier for the spawned profile."
    },
    "model_key": {
      "type": "string",
      "minLength": 1,
      "description": "Model configuration key used by the spawned run."
    },
    "summary": {
      "type": "string",
      "minLength": 1,
      "description": "Human-readable summary of the run outcome."
    },
    "artifacts": {
      "type": "array",
      "description": "Structured outputs produced by the run.",
