        "required": [
          "name",
          "type",
          "uri"
        ],
        "properties": {
          "name": {
            "type": "string",
            "minLength": 1
          },
          "type": {
            "type": "string",
            "minLength": 1
          },
          "uri": {
            "type": "string",
            "minLength": 1
          },
          "sha256": {
            "type": "string",
            "minLength": 1
          },
          "size_bytes": {
            "type": "integer",
            "minimum": 0
          }
        }
      }
    },
